window.MODULE_TITLE="Gestión de Riesgos";
window.MODULE_CSS="\n    /* ---- Laboratorio interactivo ---- */\n    .lab-container {\n      background: var(--navy);\n      border-radius: var(--radius-xl);\n      padding: 2.5rem;\n      margin: 2.5rem 0;\n    }\n    .lab-header {\n      display: flex;\n      align-items: center;\n      gap: 1rem;\n      margin-bottom: 2rem;\n      padding-bottom: 1.5rem;\n      border-bottom: 1px solid var(--navy-light);\n    }\n    .lab-icon {\n      width: 44px; height: 44px;\n      background: rgba(0,200,150,0.12);\n      border-radius: var(--radius-md);\n      display: flex; align-items: center; justify-content: center;\n      font-size: 1.3rem; flex-shrink: 0;\n    }\n    .lab-title { font-size: 1.1rem; font-weight: 700; color: var(--white); }\n    .lab-subtitle { font-size: 0.82rem; color: var(--text-faint); margin-top: 3px; }\n\n    .lab-step {\n      display: none;\n    }\n    .lab-step.active { display: block; }\n\n    .lab-step-header {\n      display: flex;\n      align-items: center;\n      gap: 0.75rem;\n      margin-bottom: 1.5rem;\n    }\n    .lab-step-num {\n      font-size: 0.65rem;\n      font-weight: 700;\n      font-family: var(--font-mono);\n      background: rgba(0,200,150,0.15);\n      color: var(--accent);\n      padding: 4px 10px;\n      border-radius: var(--radius-sm);\n      letter-spacing: 0.08em;\n      white-space: nowrap;\n    }\n    .lab-step-title {\n      font-size: 1rem;\n      font-weight: 600;\n      color: var(--white);\n    }\n\n    .lab-field {\n      margin-bottom: 1.25rem;\n    }\n    .lab-label {\n      display: block;\n      font-size: 0.75rem;\n      font-weight: 600;\n      color: var(--ice);\n      letter-spacing: 0.06em;\n      text-transform: uppercase;\n      margin-bottom: 6px;\n    }\n    .lab-input, .lab-select, .lab-textarea {\n      width: 100%;\n      background: rgba(255,255,255,0.05);\n      border: 1px solid rgba(168,200,232,0.15);\n      border-radius: var(--radius-md);\n      color: var(--white);\n      font-family: var(--font-sans);\n      font-size: 0.9rem;\n      padding: 10px 14px;\n      transition: border-color 0.2s;\n      outline: none;\n    }\n    .lab-input:focus, .lab-select:focus, .lab-textarea:focus {\n      border-color: var(--accent);\n    }\n    .lab-textarea { resize: vertical; min-height: 80px; }\n    .lab-select option { background: var(--navy-mid); color: var(--white); }\n\n    .lab-scale {\n      display: flex;\n      gap: 8px;\n      flex-wrap: wrap;\n      margin-top: 6px;\n    }\n    .lab-scale-btn {\n      width: 44px; height: 44px;\n      border-radius: var(--radius-md);\n      border: 1px solid rgba(168,200,232,0.2);\n      background: transparent;\n      color: var(--ice);\n      font-size: 0.9rem;\n      font-weight: 600;\n      cursor: pointer;\n      transition: all 0.15s;\n      font-family: var(--font-sans);\n    }\n    .lab-scale-btn:hover { border-color: var(--accent); color: var(--accent); }\n    .lab-scale-btn.selected-1, .lab-scale-btn.selected-2 { background: rgba(0,200,150,0.12); border-color: var(--accent); color: var(--accent); }\n    .lab-scale-btn.selected-3 { background: rgba(245,158,11,0.15); border-color: var(--warn); color: var(--warn); }\n    .lab-scale-btn.selected-4, .lab-scale-btn.selected-5 { background: rgba(239,68,68,0.12); border-color: var(--danger); color: #FCA5A5; }\n\n    .risk-matrix {\n      display: grid;\n      grid-template-columns: auto repeat(5, 1fr);\n      gap: 3px;\n      margin: 1.5rem 0;\n      font-size: 0.7rem;\n    }\n    .rm-cell {\n      height: 40px;\n      display: flex;\n      align-items: center;\n      justify-content: center;\n      border-radius: 4px;\n      font-weight: 600;\n      font-size: 0.65rem;\n      letter-spacing: 0.04em;\n      transition: all 0.2s;\n    }\n    .rm-label { background: transparent; color: var(--text-faint); font-size: 0.65rem; }\n    .rm-header { background: rgba(168,200,232,0.08); color: var(--ice); font-size: 0.65rem; }\n    .rm-low { background: rgba(0,200,150,0.15); color: var(--accent); }\n    .rm-med { background: rgba(245,158,11,0.15); color: var(--warn); }\n    .rm-high { background: rgba(239,68,68,0.15); color: #FCA5A5; }\n    .rm-cell.highlighted { box-shadow: 0 0 0 2px var(--accent); transform: scale(1.1); z-index: 1; position: relative; }\n\n    .result-card {\n      background: rgba(255,255,255,0.04);\n      border: 1px solid rgba(168,200,232,0.1);\n      border-radius: var(--radius-lg);\n      padding: 1.5rem;\n      margin-top: 1.5rem;\n    }\n    .result-label {\n      font-size: 0.65rem;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 0.1em;\n      color: var(--text-faint);\n      margin-bottom: 0.25rem;\n    }\n    .result-value {\n      font-size: 1.1rem;\n      font-weight: 700;\n      color: var(--white);\n    }\n    .result-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; }\n\n    .risk-level-pill {\n      display: inline-block;\n      padding: 4px 14px;\n      border-radius: 100px;\n      font-size: 0.75rem;\n      font-weight: 700;\n      letter-spacing: 0.06em;\n      text-transform: uppercase;\n    }\n    .risk-pill-low  { background: rgba(0,200,150,0.15); color: var(--accent); }\n    .risk-pill-med  { background: rgba(245,158,11,0.15); color: var(--warn); }\n    .risk-pill-high { background: rgba(239,68,68,0.15); color: #FCA5A5; }\n    .risk-pill-crit { background: rgba(239,68,68,0.25); color: #FCA5A5; border: 1px solid rgba(239,68,68,0.4); }\n\n    .lab-nav {\n      display: flex;\n      align-items: center;\n      justify-content: space-between;\n      margin-top: 2rem;\n      padding-top: 1.5rem;\n      border-top: 1px solid var(--navy-light);\n      gap: 1rem;\n    }\n    .lab-btn {\n      display: inline-flex;\n      align-items: center;\n      gap: 8px;\n      font-family: var(--font-sans);\n      font-size: 0.85rem;\n      font-weight: 600;\n      padding: 10px 20px;\n      border-radius: var(--radius-md);\n      cursor: pointer;\n      border: 1px solid rgba(168,200,232,0.2);\n      background: transparent;\n      color: var(--ice);\n      transition: all 0.2s;\n    }\n    .lab-btn:hover { border-color: var(--accent); color: var(--accent); }\n    .lab-btn--primary {\n      background: var(--accent);\n      border-color: var(--accent);\n      color: var(--navy);\n    }\n    .lab-btn--primary:hover {\n      background: #00E5AE;\n      color: var(--navy);\n    }\n    .lab-btn:disabled { opacity: 0.35; cursor: not-allowed; }\n\n    .lab-progress {\n      display: flex;\n      gap: 6px;\n      align-items: center;\n    }\n    .lab-progress-dot {\n      width: 8px; height: 8px;\n      border-radius: 50%;\n      background: rgba(168,200,232,0.2);\n      transition: background 0.2s;\n    }\n    .lab-progress-dot.done { background: var(--accent); }\n    .lab-progress-dot.current { background: var(--white); }\n\n    /* Resumen final */\n    .risk-summary-row {\n      display: grid;\n      grid-template-columns: 2fr 1fr 1fr 1fr 1fr;\n      gap: 0.5rem;\n      align-items: center;\n      padding: 10px 14px;\n      border-radius: var(--radius-md);\n      margin-bottom: 6px;\n      font-size: 0.85rem;\n    }\n    .rsr-header {\n      font-size: 0.65rem;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 0.08em;\n      color: var(--text-faint);\n      margin-bottom: 0.5rem;\n    }\n    .rsr-data { background: rgba(255,255,255,0.04); }\n  ";
window.SLIDES=[{"type": "portada", "eyebrow": "Curso ISO/IEC 27001 · ISO/IEC 27701", "title": "Gestión de Riesgos", "intro": "Este módulo contiene 7 lecciones con teoría, ejemplos normativos y preguntas de comprobación.", "meta": ["📖 7 lecciones", "✅ Quiz por lección", "🔐 ISO/IEC 27001 · 27701"]}, {"type": "texto", "heading": "Marco conceptual del riesgo de seguridad", "html": "<p>\n        La gestión del riesgo es el mecanismo central del SGSI. Todo lo demás — los controles, la documentación, las auditorías — existe para gestionar riesgos. Comprender el vocabulario y el modelo conceptual con precisión es imprescindible para implementar un proceso de riesgo que sea robusto y no solo formal.\n      </p>"}, {"type": "tabla", "headers": ["Término", "Definición", "Ejemplo en SI"], "rows": [["Activo", "Cualquier cosa que tiene valor para la organización", "Base de datos de clientes, servidor ERP, reputación de marca"], ["Amenaza", "Causa potencial de un incidente no deseado que puede resultar en daño", "Ransomware, phishing dirigido, empleado malicioso, desastre natural"], ["Vulnerabilidad", "Debilidad de un activo que puede ser explotada por una amenaza", "Software sin parchear, contraseñas débiles, ausencia de segmentación de red"], ["Riesgo", "Efecto de la incertidumbre sobre los objetivos. Combinación de probabilidad de ocurrencia e impacto", "Probabilidad de que ransomware cifre el ERP × impacto en operaciones"], ["Impacto", "Consecuencia de un incidente de seguridad sobre los objetivos organizativos", "Pérdida económica, daño reputacional, sanción regulatoria, interrupción operativa"], ["Riesgo inherente", "Riesgo antes de aplicar controles", "Nivel de exposición sin medidas de seguridad"], ["Riesgo residual", "Riesgo que permanece después de aplicar controles", "Nivel de exposición una vez implementados los controles seleccionados"], ["Apetito de riesgo", "Nivel de riesgo que la organización está dispuesta a aceptar", "Definido por la dirección como umbral de aceptación del riesgo residual"], ["Propietario del riesgo", "Persona o entidad con responsabilidad y autoridad para gestionar el riesgo", "El Director de Operaciones es propietario del riesgo de continuidad del ERP"]]}, {"type": "texto", "heading": "El modelo Amenaza → Vulnerabilidad → Impacto", "html": "<p>\n        El riesgo de seguridad de la información se materializa cuando una <strong>amenaza</strong> explota una <strong>vulnerabilidad</strong> de un <strong>activo</strong>, generando un <strong>impacto</strong> sobre la organización. Este modelo es la base de cualquier metodología de análisis de riesgos.\n      </p>"}, {"type": "callout", "variant": "legal", "label": "La tríada CIA como eje del impacto", "html": "<p>ISO 27001 evalúa el impacto de los riesgos en términos de las tres propiedades de la información: <strong>Confidencialidad</strong> (acceso solo a quienes están autorizados), <strong>Integridad</strong> (exactitud y completitud de la información) y <strong>Disponibilidad</strong> (accesible cuando se necesita). Un análisis de riesgos robusto valora el impacto potencial sobre las tres dimensiones para cada activo crítico.</p>"}, {"type": "texto", "heading": "El proceso de gestión del riesgo según ISO 27005", "html": "<p>El proceso completo consta de estas fases, que se iteran continuamente:</p><ol style=\"margin:1rem 0 0 1.5rem; color:var(--text-muted); line-height:2.5; font-size:0.95rem;\">\n<li><strong>Establecimiento del contexto</strong> — Definir criterios, alcance y método.</li>\n<li><strong>Identificación del riesgo</strong> — Qué puede ocurrir, dónde, cómo y por qué.</li>\n<li><strong>Análisis del riesgo</strong> — Estimar probabilidad e impacto.</li>\n<li><strong>Evaluación del riesgo</strong> — Comparar con criterios y priorizar.</li>\n<li><strong>Tratamiento del riesgo</strong> — Seleccionar y aplicar opciones de tratamiento.</li>\n<li><strong>Aceptación del riesgo</strong> — Decisión formal sobre el riesgo residual.</li>\n<li><strong>Comunicación y consulta</strong> — Proceso transversal a todas las fases.</li>\n<li><strong>Monitorización y revisión</strong> — Proceso continuo de supervisión.</li>\n</ol>"}, {"type": "quiz", "id": "q-1", "num": 1, "total": 4, "question": "Una empresa tiene un servidor web con una vulnerabilidad conocida (CVE sin parchear) que permite ejecución remota de código. El servidor aloja datos de clientes. ¿Cuál es la relación correcta entre los elementos del riesgo?", "options": ["El servidor es la amenaza; el CVE es el activo; los datos de clientes son la vulnerabilidad.", "El servidor y los datos de clientes son activos; la vulnerabilidad es el CVE sin parchear; la amenaza es un atacante que explota ese CVE; el impacto es la pérdida de confidencialidad de los datos.", "El CVE es la amenaza; el servidor es la vulnerabilidad; el impacto es la ejecución remota de código.", "Los datos de clientes son la amenaza porque atraen a atacantes."], "correctIndex": 1, "feedbackOk": "✅ La distinción entre amenaza, vulnerabilidad y activo es fundamental. Elactivotiene valor (servidor + datos). Lavulnerabilidades la debilidad explotable (CVE sin parchear). Laamenazaes el agente o evento que explota la vulnerabilidad (atacante). Elimpactoes la consecuencia si el riesgo se materializa (exposición de datos, interrupción del servicio).", "feedbackKo": "❌ La distinción entre amenaza, vulnerabilidad y activo es fundamental. Elactivotiene valor (servidor + datos). Lavulnerabilidades la debilidad explotable (CVE sin parchear). Laamenazaes el agente o evento que explota la vulnerabilidad (atacante). Elimpactoes la consecuencia si el riesgo se materializa (exposición de datos, interrupción del servicio)."}, {"type": "texto", "heading": "ISO/IEC 27005:2022 — metodología de gestión del riesgo", "html": "<p>\n        ISO/IEC 27005:2022 es la guía metodológica oficial para la gestión del riesgo de seguridad de la información. La tercera edición (2022) introdujo cambios conceptuales importantes respecto a la versión anterior, especialmente la adopción del <strong>enfoque basado en escenarios de riesgo</strong> como alternativa al enfoque tradicional basado en activos.\n      </p>"}, {"type": "clausebox", "ref": "Enfoque clásico", "title": "Basado en activos", "html": "<p style=\"font-size:0.875rem; color:var(--text-muted); margin-bottom:0.75rem;\">\n            Parte del inventario de activos. Para cada activo se identifican amenazas, vulnerabilidades y se estima el riesgo.\n          </p><p style=\"font-size:0.8rem; color:var(--text-faint);\"><strong>Ventaja:</strong> muy exhaustivo y trazable.<br/><strong>Limitación:</strong> puede ser extremadamente laborioso en organizaciones grandes.</p>"}, {"type": "clausebox", "ref": "Enfoque moderno", "title": "Basado en escenarios", "html": "<p style=\"font-size:0.875rem; color:var(--text-muted); margin-bottom:0.75rem;\">\n            Parte de escenarios de riesgo plausibles (ej: \"ransomware en sistemas productivos\"). Se analiza su probabilidad e impacto sin enumerar todos los activos.\n          </p><p style=\"font-size:0.8rem; color:var(--text-faint);\"><strong>Ventaja:</strong> más ágil y orientado a negocio.<br/><strong>Limitación:</strong> requiere experiencia para definir escenarios representativos.</p>"}, {"type": "callout", "variant": "info", "label": "¿Cuál usar en la práctica?", "html": "<p>ISO 27001 no prescribe ninguno. La elección depende del contexto: organizaciones con infraestructuras complejas y equipos maduros suelen beneficiarse del enfoque basado en activos (más exhaustivo). Organizaciones ágiles o en fases iniciales de implementación suelen encontrar el enfoque por escenarios más manejable. La norma permite combinar ambos.</p>"}, {"type": "texto", "heading": "Criterios de riesgo: la base del proceso", "html": "<p>Antes de evaluar ningún riesgo, la organización debe establecer los <strong>criterios de riesgo</strong>. Sin criterios previos, la evaluación es subjetiva e inconsistente. Los criterios deben definir:</p>"}, {"type": "tabla", "headers": ["Criterio", "Descripción", "Ejemplo"], "rows": [["Escala de probabilidad", "Cómo se mide la probabilidad de ocurrencia", "1=Muy baja (&lt;1 vez en 10 años), 2=Baja (1 vez en 5 años), 3=Media (1 vez al año), 4=Alta (varias veces al año), 5=Muy alta (mensual o más)"], ["Escala de impacto", "Cómo se mide la gravedad del impacto", "1=Insignificante, 2=Menor, 3=Moderado, 4=Mayor, 5=Catastrófico"], ["Matriz de riesgo", "Combinación de probabilidad × impacto", "Niveles: bajo (1–4), medio (5–9), alto (10–16), crítico (17–25)"], ["Nivel de aceptación", "Nivel de riesgo residual que la dirección acepta sin tratamiento adicional", "Riesgos ≤6 se aceptan; riesgos 7–12 requieren plan de mejora; riesgos ≥13 requieren acción inmediata"]]}, {"type": "callout", "variant": "alerta", "label": "Los criterios deben aprobarse antes del análisis", "html": "<p>Un error frecuente: definir los criterios <em>después</em> de realizar el análisis, ajustándolos para que los resultados sean más convenientes. ISO 27001 exige que los criterios se establezcan <em>antes</em> de comenzar la evaluación y que sean aprobados por la dirección. Los auditores verifican la fecha de aprobación de los criterios vs la fecha del análisis.</p>"}, {"type": "quiz", "id": "q-2", "num": 2, "total": 4, "question": "Una organización realiza su primera evaluación de riesgos. El analista valora la probabilidad de cada amenaza según su experiencia personal, sin una escala definida previamente. ¿Qué problema fundamental presenta este enfoque?", "options": ["Ninguno, la experiencia del analista es una fuente válida de criterio.", "Viola el requisito de consistencia de ISO 27001 (6.1.2): sin escala definida, dos analistas diferentes producirán resultados incomparables, y la organización no puede demostrar que el proceso es reproducible.", "Solo es un problema si la organización tiene más de un analista de riesgos.", "El enfoque cualitativo siempre es aceptable según ISO 27005."], "correctIndex": 1, "feedbackOk": "✅ La cláusula 6.1.2 de ISO 27001 exige que el proceso produzca resultados \"consistentes, válidos y comparables\". Sin criterios documentados y aprobados previamente, el proceso depende del criterio individual de quien lo ejecuta — lo que lo hace subjetivo, no reproducible y, por tanto, no conforme con la norma.", "feedbackKo": "❌ La cláusula 6.1.2 de ISO 27001 exige que el proceso produzca resultados \"consistentes, válidos y comparables\". Sin criterios documentados y aprobados previamente, el proceso depende del criterio individual de quien lo ejecuta — lo que lo hace subjetivo, no reproducible y, por tanto, no conforme con la norma."}, {"type": "texto", "heading": "MAGERIT v3 — la metodología nacional de referencia", "html": "<p>\n        MAGERIT (Metodología de Análisis y Gestión de Riesgos de los Sistemas de Información) es la metodología oficial desarrollada por el Consejo Superior de Administración Electrónica de España. Es de libre acceso, está alineada con ISO 27005 y es la referencia metodológica principal en el contexto español, especialmente en el sector público y en organizaciones que deben cumplir con el Esquema Nacional de Seguridad (ENS).\n      </p>"}, {"type": "callout", "variant": "legal", "label": "MAGERIT y la herramienta PILAR", "html": "<p>El CCN proporciona la herramienta <strong>PILAR</strong> (Procedimiento Informático-Lógico para el Análisis de Riesgos) que implementa la metodología MAGERIT. PILAR es gratuita para la Administración Pública y tiene versión comercial para el sector privado. Automatiza el análisis de riesgos, el catálogo de amenazas y la generación de informes. Ver: <a href=\"https://www.ccn-cert.cni.es/es/herramientas/herramientas-de-auditoria-y-herramientas-ccn/magerit.html\" rel=\"noopener noreferrer\" style=\"color:var(--accent);\" target=\"_blank\">CCN-CERT — MAGERIT ↗</a></p>"}, {"type": "tabla", "headers": ["Libro", "Contenido", "Para quién"], "rows": [["Libro 1 — Método", "El proceso de análisis y gestión de riesgos: pasos, artefactos y resultados esperados", "Implementadores y gestores del proceso de riesgo"], ["Libro 2 — Catálogo de Elementos", "Catálogo de tipos de activos, dimensiones de valoración, amenazas típicas y salvaguardas", "Analistas que ejecutan el análisis de riesgos"], ["Libro 3 — Guía de Técnicas", "Técnicas concretas para el análisis: árboles de ataque, análisis Monte Carlo, tablas de riesgo", "Analistas con necesidad de técnicas avanzadas"]]}, {"type": "texto", "heading": "Tipos de activos en MAGERIT", "html": "<p>MAGERIT clasifica los activos en una taxonomía jerárquica. Conocerla facilita enormemente la construcción del inventario:</p>"}, {"type": "tabla", "headers": ["Tipo", "Subtipo", "Ejemplos"], "rows": [["[I] Información", "Datos de carácter personal", "Ficheros de empleados, clientes, pacientes"], ["Datos clasificados", "Secretos comerciales, propiedad intelectual"], ["Credenciales", "Contraseñas, certificados digitales, tokens"], ["[S] Servicios", "Servicios internos y externos", "ERP, correo electrónico, portal web, VPN"], ["[SW] Software", "Aplicaciones, SO, middleware", "SAP, Windows Server, Apache, bases de datos"], ["[HW] Hardware", "Equipos físicos", "Servidores, PCs, switches, firewalls, móviles"], ["[COM] Comunicaciones", "Redes e infraestructura de comunicación", "LAN corporativa, MPLS, conexiones cloud"], ["[SI] Soportes", "Medios de almacenamiento", "Discos, USB, cintas de backup, papel"], ["[AUX] Auxiliares", "Infraestructura de soporte", "SAI, generadores, climatización, cableado"], ["[L] Instalaciones", "Locales y ubicaciones", "CPD, oficinas, salas de reunión"], ["[P] Personal", "Personas con roles en el sistema", "Administradores, usuarios, proveedores externos"]]}, {"type": "texto", "heading": "Dimensiones de valoración en MAGERIT", "html": "<p>MAGERIT valora los activos en cinco dimensiones que amplían la tríada CIA:</p><ul style=\"margin:0.75rem 0 0 1.5rem; color:var(--text-muted); line-height:2.2; font-size:0.95rem;\">\n<li><strong>[C] Confidencialidad</strong> — Daño si el activo es conocido por quien no debe.</li>\n<li><strong>[I] Integridad</strong> — Daño si el activo es modificado de forma inapropiada.</li>\n<li><strong>[D] Disponibilidad</strong> — Daño si el activo no está disponible cuando se necesita.</li>\n<li><strong>[A] Autenticidad</strong> — Daño si el activo no acredita correctamente su origen.</li>\n<li><strong>[T] Trazabilidad</strong> — Daño si no puede rastrearse quién accedió o modificó el activo.</li>\n</ul>"}, {"type": "quiz", "id": "q-3", "num": 3, "total": 4, "question": "Una organización pública española implementa un SGSI alineado con el ENS. El equipo de análisis de riesgos propone usar OCTAVE en lugar de MAGERIT. ¿Es esto aceptable según ISO 27001?", "options": ["No, las organizaciones sujetas al ENS están obligadas a usar MAGERIT.", "Sí. ISO 27001 no prescribe ninguna metodología específica. Cualquier metodología documentada que satisfaga los requisitos de la cláusula 6.1.2 es aceptable. Para el ENS, sin embargo, el uso de MAGERIT/PILAR está recomendado y facilita el cumplimiento.", "No, ISO 27005 obliga a usar MAGERIT en el contexto europeo.", "Solo es aceptable si OCTAVE está homologada por el CCN-CERT."], "correctIndex": 1, "feedbackOk": "✅ ISO 27001 es neutral respecto a metodologías. Lo que importa es que el proceso satisfaga los requisitos de la cláusula 6.1.2 (consistencia, validez, comparabilidad) y esté documentado. En el contexto ENS, MAGERIT/PILAR está fuertemente recomendado por el CCN y facilita el cumplimiento, pero no es obligatorio según ISO 27001.", "feedbackKo": "❌ ISO 27001 es neutral respecto a metodologías. Lo que importa es que el proceso satisfaga los requisitos de la cláusula 6.1.2 (consistencia, validez, comparabilidad) y esté documentado. En el contexto ENS, MAGERIT/PILAR está fuertemente recomendado por el CCN y facilita el cumplimiento, pero no es obligatorio según ISO 27001."}, {"type": "texto", "heading": "Identificación y valoración de activos", "html": "<p>El inventario de activos es el punto de partida del análisis de riesgos basado en activos. Un inventario mal construido — incompleto, con activos mal valorados o sin propietarios asignados — compromete toda la evaluación de riesgos que se construya sobre él.</p>"}, {"type": "tabla", "headers": ["Campo", "Descripción", "Observaciones"], "rows": [["ID único", "Identificador del activo", "Permite referencias cruzadas con la evaluación de riesgos"], ["Nombre", "Denominación descriptiva", "Suficientemente específico para identificar unívocamente el activo"], ["Tipo", "Categoría (información, servicio, software, hardware...)", "Usar la taxonomía MAGERIT o equivalente"], ["Propietario", "Persona responsable del activo", "Obligatorio según control 5.9 del Anexo A"], ["Clasificación", "Nivel de sensibilidad de la información", "Público, Interno, Confidencial, Secreto"], ["Valoración C/I/D", "Valor para la organización en cada dimensión", "Escala 1–5 según criterios aprobados"], ["Dependencias", "Activos de los que depende este activo", "Crítico para propagar valoraciones en cadena"], ["Ubicación", "Dónde se encuentra físicamente o lógicamente", "CPD propio, cloud AWS, oficina Madrid..."]]}, {"type": "callout", "variant": "info", "label": "La valoración de activos: valor para el negocio, no coste de reposición", "html": "<p>Un error frecuente es valorar los activos por su coste de adquisición o reposición. La valoración correcta mide el <strong>daño que causaría a la organización</strong> la pérdida de confidencialidad, integridad o disponibilidad de ese activo. Una base de datos de clientes que costó 5.000€ en desarrollo puede tener un valor de impacto de millones en caso de fuga — es el daño al negocio lo que debe valorarse.</p>"}, {"type": "texto", "heading": "Activos críticos vs activos de soporte", "html": "<p>No todos los activos tienen el mismo peso en el análisis. MAGERIT distingue entre:</p><ul style=\"margin:0.75rem 0 0 1.5rem; color:var(--text-muted); line-height:2.2; font-size:0.95rem;\">\n<li><strong>Activos esenciales</strong> (información y servicios): los que directamente sustentan la misión de la organización. Son el foco principal del análisis.</li>\n<li><strong>Activos de soporte</strong> (hardware, software, redes, personas, instalaciones): los que soportan a los esenciales. Su valoración se deriva de los activos esenciales que sustentan.</li>\n</ul>"}, {"type": "texto", "heading": "Análisis de amenazas y vulnerabilidades", "html": "<p>Una vez identificados y valorados los activos, el análisis de amenazas y vulnerabilidades determina <em>qué puede ocurrirle</em> a cada activo y <em>con qué facilidad</em>. Esta fase es donde el análisis de riesgos adquiere su dimensión práctica y operativa.</p>"}, {"type": "tabla", "headers": ["Categoría", "Amenaza", "Afecta a"], "rows": [["[N] Naturales", "Fuego", "HW, SI, L, AUX"], ["Inundación", "HW, SI, L, AUX"], ["Terremoto / desastre natural", "HW, SI, L, AUX, COM"], ["[I] Industriales", "Corte de suministro eléctrico", "HW, AUX, COM"], ["Fallo de comunicaciones", "COM, S"], ["Fallo de servicios de soporte", "AUX, HW"], ["[E] Errores y fallos no intencionados", "Errores de usuarios", "I, SW, S"], ["Errores de administración", "HW, SW, COM, S"], ["Vulnerabilidades de software", "SW, I"], ["Destrucción de información", "I, SI"], ["[A] Ataques intencionados", "Acceso no autorizado", "I, S, SW"], ["Suplantación de identidad", "I, S, P"], ["Ataques de denegación de servicio", "S, COM"], ["Infección por malware / ransomware", "SW, I, HW"], ["Fuga de información", "I, P"]]}, {"type": "texto", "heading": "Fuentes de información sobre amenazas (Threat Intelligence)", "html": "<p>El control <strong>5.7 del Anexo A 2022 (Threat Intelligence)</strong> — uno de los 11 nuevos — exige que la organización recopile y analice información sobre amenazas relevantes para su contexto. Fuentes recomendadas:</p><p style=\"font-size:0.75rem; font-weight:700; color:var(--navy); margin-bottom:0.5rem;\">Fuentes institucionales</p><ul style=\"list-style:none; font-size:0.82rem; color:var(--text-muted); line-height:2;\">\n<li>→ <a href=\"https://www.ccn-cert.cni.es/es/informes/informes-ccn-cert-publicos.html\" rel=\"noopener noreferrer\" style=\"color:var(--steel-mid);\" target=\"_blank\">CCN-CERT Informes de Amenazas ↗</a></li>\n<li>→ <a href=\"https://www.enisa.europa.eu/topics/threat-landscape\" rel=\"noopener noreferrer\" style=\"color:var(--steel-mid);\" target=\"_blank\">ENISA Threat Landscape ↗</a></li>\n<li>→ <a href=\"https://nvd.nist.gov\" rel=\"noopener noreferrer\" style=\"color:var(--steel-mid);\" target=\"_blank\">NVD — NIST Vulnerabilidades ↗</a></li>\n</ul><p style=\"font-size:0.75rem; font-weight:700; color:var(--navy); margin-bottom:0.5rem;\">Fuentes técnicas</p><ul style=\"list-style:none; font-size:0.82rem; color:var(--text-muted); line-height:2;\">\n<li>→ <a href=\"https://attack.mitre.org\" rel=\"noopener noreferrer\" style=\"color:var(--steel-mid);\" target=\"_blank\">MITRE ATT&amp;CK ↗</a></li>\n<li>→ <a href=\"https://owasp.org/www-project-top-ten/\" rel=\"noopener noreferrer\" style=\"color:var(--steel-mid);\" target=\"_blank\">OWASP Top 10 ↗</a></li>\n<li>→ ISACs sectoriales (financiero, sanitario, energía)</li>\n</ul>"}, {"type": "texto", "heading": "Opciones de tratamiento del riesgo", "html": "<p>\n        Una vez evaluados y priorizados los riesgos, la organización debe decidir qué hace con cada uno. ISO 27001 contempla cuatro opciones de tratamiento, que no son mutuamente excluyentes: un mismo riesgo puede ser tratado con una combinación de ellas.\n      </p>"}, {"type": "clausebox", "ref": "Opción 1", "title": "Modificar el riesgo (mitigar)", "html": "<p style=\"font-size:0.9rem; color:var(--text-muted);\">Implementar controles para reducir la probabilidad de ocurrencia, el impacto o ambos. Es la opción más frecuente y la que genera la mayor parte del trabajo de implementación del SGSI. Los controles se seleccionan del Anexo A de ISO 27001, de ISO 27002, o de otras fuentes justificadas. La modificación nunca elimina completamente el riesgo — siempre queda un riesgo residual.</p>"}, {"type": "clausebox", "ref": "Opción 2", "title": "Retener el riesgo (aceptar)", "html": "<p style=\"font-size:0.9rem; color:var(--text-muted);\">Aceptar conscientemente el riesgo cuando está dentro del nivel de apetito de riesgo definido por la dirección, o cuando el coste del tratamiento supera el valor del activo protegido. La aceptación debe ser una <strong>decisión informada y documentada</strong>, aprobada por el propietario del riesgo y/o la alta dirección. No es \"ignorar el riesgo\" — es aceptarlo con pleno conocimiento de su existencia y magnitud.</p>"}, {"type": "clausebox", "ref": "Opción 3", "title": "Evitar el riesgo (eliminar)", "html": "<p style=\"font-size:0.9rem; color:var(--text-muted);\">Eliminar la actividad, proceso o sistema que genera el riesgo. Es la opción más radical y la más efectiva — si la fuente del riesgo no existe, el riesgo tampoco. Sin embargo, suele tener un coste de negocio elevado (dejar de ofrecer un servicio, prescindir de un proveedor, abandonar una tecnología). Debe considerarse cuando el riesgo es tan elevado que no puede mitigarse a un nivel aceptable con controles razonables.</p>"}, {"type": "clausebox", "ref": "Opción 4", "title": "Compartir el riesgo (transferir)", "html": "<p style=\"font-size:0.9rem; color:var(--text-muted);\">Transferir o compartir el impacto financiero del riesgo con terceros mediante seguros de ciberriesgo, contratos con proveedores que incluyan penalizaciones por incidentes, o subcontratación de servicios críticos a terceros especializados. <strong>Importante:</strong> compartir el riesgo no transfiere la responsabilidad legal ni regulatoria — si un proveedor subcontratado sufre una brecha que expone datos de clientes, la organización contratante sigue siendo responsable ante el RGPD.</p>"}, {"type": "callout", "variant": "clave", "label": "El riesgo residual y la aceptación formal", "html": "<p>Después de aplicar las opciones de tratamiento, siempre queda un riesgo residual. Este riesgo residual debe ser evaluado formalmente y aceptado por el propietario del riesgo y/o la alta dirección. ISO 27001 exige evidencia documentada de esta aceptación. Un plan de tratamiento sin proceso de aceptación formal del riesgo residual es una no conformidad típica.</p>"}, {"type": "quiz", "id": "q-4", "num": 4, "total": 4, "question": "Una empresa contrata un seguro de ciberriesgo por 2M€ y considera que el riesgo de ransomware está tratado mediante \"compartir\". El CISO no implementa ningún control adicional. ¿Es este enfoque correcto?", "options": ["Sí, si el seguro cubre el coste del incidente, el riesgo está adecuadamente tratado.", "No. Compartir el riesgo transfiere el impacto financiero pero no reduce la probabilidad ni protege los activos. La organización sigue expuesta al incidente. Además, la responsabilidad regulatoria (RGPD, NIS2) no se transfiere al asegurador. ISO 27001 esperaría también controles de modificación del riesgo.", "Sí, si la cobertura del seguro supera el valor de los activos en riesgo.", "Depende de si el nivel de riesgo residual está dentro del apetito de riesgo aprobado por la dirección."], "correctIndex": 1, "feedbackOk": "✅ El seguro de ciberriesgo es una herramienta financiera que mitiga el impacto económico de un incidente, pero no previene el incidente. Una organización certificada bajo ISO 27001 que depende exclusivamente de seguros sin controles preventivos difícilmente satisfaría los requisitos del Anexo A. Adicionalmente, las responsabilidades regulatorias (notificación a la AEPD, sanciones RGPD) no son asegurables en el sentido de que el seguro no exime de la responsabilidad legal.", "feedbackKo": "❌ El seguro de ciberriesgo es una herramienta financiera que mitiga el impacto económico de un incidente, pero no previene el incidente. Una organización certificada bajo ISO 27001 que depende exclusivamente de seguros sin controles preventivos difícilmente satisfaría los requisitos del Anexo A. Adicionalmente, las responsabilidades regulatorias (notificación a la AEPD, sanciones RGPD) no son asegurables en el sentido de que el seguro no exime de la responsabilidad legal."}, {"type": "texto", "heading": "Laboratorio: construye tu primera evaluación de riesgos", "html": "<p>\n        En este laboratorio construirás una evaluación de riesgos real paso a paso, aplicando la metodología vista en las lecciones anteriores. El ejercicio simula el análisis de riesgos de una empresa del sector servicios con infraestructura cloud y datos de clientes.\n      </p><p style=\"margin-top:0.75rem; font-size:0.9rem; color:var(--text-muted);\">\n        Completa los 5 pasos del laboratorio. Al finalizar obtendrás el perfil de riesgo del activo analizado con su nivel de riesgo inherente, riesgo residual y la decisión de tratamiento recomendada.\n      </p>"}, {"type": "rawhtml", "html": "<div class=\"lab-container\" id=\"risk-lab\">\n<div class=\"lab-header\">\n<div class=\"lab-icon\">🔬</div>\n<div>\n<p class=\"lab-title\">Laboratorio de Evaluación de Riesgos</p>\n<p class=\"lab-subtitle\">ISO/IEC 27005:2022 · Metodología basada en activos</p>\n</div>\n<div class=\"lab-progress\" id=\"lab-progress\" style=\"margin-left:auto;\">\n<div class=\"lab-progress-dot current\" id=\"dot-0\"></div>\n<div class=\"lab-progress-dot\" id=\"dot-1\"></div>\n<div class=\"lab-progress-dot\" id=\"dot-2\"></div>\n<div class=\"lab-progress-dot\" id=\"dot-3\"></div>\n<div class=\"lab-progress-dot\" id=\"dot-4\"></div>\n</div>\n</div>\n<!-- PASO 1: Identificación del activo -->\n<div class=\"lab-step active\" id=\"step-0\">\n<div class=\"lab-step-header\">\n<span class=\"lab-step-num\">PASO 1 DE 5</span>\n<span class=\"lab-step-title\">Identificación del activo</span>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Nombre del activo *</label>\n<input class=\"lab-input\" id=\"asset-name\" placeholder=\"Ej: Base de datos de clientes (CRM)\" type=\"text\" value=\"Base de datos de clientes (CRM)\"/>\n</div>\n<div style=\"display:grid; grid-template-columns:1fr 1fr; gap:1rem;\">\n<div class=\"lab-field\">\n<label class=\"lab-label\">Tipo de activo (MAGERIT)</label>\n<select class=\"lab-select\" id=\"asset-type\">\n<option value=\"I\">Información [I]</option>\n<option value=\"S\">Servicio [S]</option>\n<option value=\"SW\">Software [SW]</option>\n<option value=\"HW\">Hardware [HW]</option>\n<option value=\"COM\">Comunicaciones [COM]</option>\n<option value=\"SI\">Soporte de información [SI]</option>\n<option value=\"P\">Personal [P]</option>\n</select>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Propietario del activo</label>\n<input class=\"lab-input\" id=\"asset-owner\" placeholder=\"Ej: Director Comercial\" type=\"text\" value=\"Director Comercial\"/>\n</div>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Descripción breve</label>\n<textarea class=\"lab-textarea\" id=\"asset-desc\" placeholder=\"Qué contiene, para qué se usa y por qué es importante para el negocio\">Base de datos que almacena datos personales y comerciales de 45.000 clientes activos. Alimenta el sistema de facturación y las campañas de marketing. Reside en servidor cloud AWS (RDS). Acceso desde la red corporativa y VPN.</textarea>\n</div>\n<div class=\"lab-nav\">\n<span style=\"font-size:0.8rem; color:var(--text-faint);\">Los campos tienen valores de ejemplo — puedes modificarlos</span>\n<button class=\"lab-btn lab-btn--primary\" onclick=\"labNext(0)\">Siguiente: Valorar el activo →</button>\n</div>\n</div>\n<!-- PASO 2: Valoración del activo -->\n<div class=\"lab-step\" id=\"step-1\">\n<div class=\"lab-step-header\">\n<span class=\"lab-step-num\">PASO 2 DE 5</span>\n<span class=\"lab-step-title\">Valoración del activo (CIA)</span>\n</div>\n<p style=\"color:var(--ice); font-size:0.9rem; margin-bottom:1.5rem; line-height:1.7;\">\n            Valora el daño que causaría a la organización la pérdida de cada dimensión de seguridad para este activo. Escala: <span style=\"color:var(--accent);\">1=Insignificante</span> · 2=Menor · <span style=\"color:var(--warn);\">3=Moderado</span> · 4=Mayor · <span style=\"color:#FCA5A5;\">5=Catastrófico</span>\n</p>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Confidencialidad — ¿Qué daño causaría que personas no autorizadas accedieran a este activo?</label>\n<div class=\"lab-scale\" id=\"scale-c\">\n<button class=\"lab-scale-btn\" onclick=\"setScale('c',1,this)\">1</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('c',2,this)\">2</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('c',3,this)\">3</button>\n<button class=\"lab-scale-btn selected-4\" onclick=\"setScale('c',4,this)\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('c',5,this)\">5</button>\n</div>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Integridad — ¿Qué daño causaría que este activo fuera modificado de forma no autorizada?</label>\n<div class=\"lab-scale\" id=\"scale-i\">\n<button class=\"lab-scale-btn\" onclick=\"setScale('i',1,this)\">1</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('i',2,this)\">2</button>\n<button class=\"lab-scale-btn selected-4\" onclick=\"setScale('i',3,this)\">3</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('i',4,this)\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('i',5,this)\">5</button>\n</div>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Disponibilidad — ¿Qué daño causaría que este activo no estuviera accesible cuando se necesita?</label>\n<div class=\"lab-scale\" id=\"scale-d\">\n<button class=\"lab-scale-btn\" onclick=\"setScale('d',1,this)\">1</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('d',2,this)\">2</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('d',3,this)\">3</button>\n<button class=\"lab-scale-btn selected-4\" onclick=\"setScale('d',4,this)\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setScale('d',5,this)\">5</button>\n</div>\n</div>\n<div class=\"result-card\" id=\"asset-value-card\" style=\"margin-top:1rem;\">\n<div class=\"result-grid\">\n<div><p class=\"result-label\">Valor máximo del activo</p><p class=\"result-value\" id=\"asset-max-val\">4</p></div>\n<div><p class=\"result-label\">Clasificación</p><p class=\"result-value\" id=\"asset-class\">Confidencial</p></div>\n</div>\n</div>\n<div class=\"lab-nav\">\n<button class=\"lab-btn\" onclick=\"labPrev(1)\">← Volver</button>\n<button class=\"lab-btn lab-btn--primary\" onclick=\"labNext(1)\">Siguiente: Amenaza y vulnerabilidad →</button>\n</div>\n</div>\n<!-- PASO 3: Amenaza y vulnerabilidad -->\n<div class=\"lab-step\" id=\"step-2\">\n<div class=\"lab-step-header\">\n<span class=\"lab-step-num\">PASO 3 DE 5</span>\n<span class=\"lab-step-title\">Identificación de amenaza y vulnerabilidad</span>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Amenaza identificada</label>\n<select class=\"lab-select\" id=\"threat-select\" onchange=\"updateThreatHelp()\">\n<option value=\"ransomware\">Infección por ransomware</option>\n<option value=\"acceso_no_auth\">Acceso no autorizado (externo)</option>\n<option value=\"empleado_mal\">Empleado malicioso / insider threat</option>\n<option value=\"fuga\">Fuga de información accidental</option>\n<option value=\"phishing\">Phishing dirigido (spear phishing)</option>\n<option value=\"dos\">Ataque de denegación de servicio</option>\n<option value=\"fallo_hw\">Fallo de hardware / proveedor cloud</option>\n<option value=\"error_config\">Error de configuración</option>\n</select>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Vulnerabilidad explotada por esta amenaza</label>\n<input class=\"lab-input\" id=\"vuln-input\" type=\"text\" value=\"Ausencia de copias de seguridad offline y tiempo de recuperación (RTO) no definido\"/>\n</div>\n<div id=\"threat-help\" style=\"background:rgba(0,200,150,0.06); border:1px solid rgba(0,200,150,0.15); border-radius:var(--radius-md); padding:1rem; margin-bottom:1rem;\">\n<p style=\"font-size:0.75rem; font-weight:600; color:var(--accent); margin-bottom:0.4rem;\">💡 Controles relevantes del Anexo A</p>\n<p id=\"threat-controls\" style=\"font-size:0.82rem; color:var(--ice); line-height:1.7;\">8.13 (Backup), 8.14 (Redundancia), 5.30 (Continuidad TIC), 8.8 (Gestión de vulnerabilidades técnicas)</p>\n</div>\n<div class=\"lab-nav\">\n<button class=\"lab-btn\" onclick=\"labPrev(2)\">← Volver</button>\n<button class=\"lab-btn lab-btn--primary\" onclick=\"labNext(2)\">Siguiente: Estimar el riesgo →</button>\n</div>\n</div>\n<!-- PASO 4: Estimación del riesgo -->\n<div class=\"lab-step\" id=\"step-3\">\n<div class=\"lab-step-header\">\n<span class=\"lab-step-num\">PASO 4 DE 5</span>\n<span class=\"lab-step-title\">Estimación del riesgo inherente y residual</span>\n</div>\n<p style=\"color:var(--ice); font-size:0.9rem; margin-bottom:1.5rem; line-height:1.7;\">\n            Estima la <strong>probabilidad</strong> de que la amenaza se materialice y el <strong>impacto</strong> resultante. El riesgo inherente es el nivel sin controles. El riesgo residual es el nivel después de los controles existentes.\n          </p>\n<div style=\"display:grid; grid-template-columns:1fr 1fr; gap:2rem;\">\n<div>\n<p style=\"font-size:0.8rem; font-weight:600; color:var(--ice); margin-bottom:1rem; text-transform:uppercase; letter-spacing:0.08em;\">Riesgo Inherente (sin controles)</p>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Probabilidad</label>\n<div class=\"lab-scale\" id=\"scale-prob-inh\">\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_inh',1,this)\" title=\"Muy baja\">1</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_inh',2,this)\" title=\"Baja\">2</button>\n<button class=\"lab-scale-btn selected-3\" onclick=\"setRisk('prob_inh',3,this)\" title=\"Media\">3</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_inh',4,this)\" title=\"Alta\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_inh',5,this)\" title=\"Muy alta\">5</button>\n</div>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Impacto</label>\n<div class=\"lab-scale\" id=\"scale-imp-inh\">\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_inh',1,this)\">1</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_inh',2,this)\">2</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_inh',3,this)\">3</button>\n<button class=\"lab-scale-btn selected-4\" onclick=\"setRisk('imp_inh',4,this)\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_inh',5,this)\">5</button>\n</div>\n</div>\n<div class=\"result-card\">\n<p class=\"result-label\">Nivel de riesgo inherente</p>\n<p class=\"result-value\" id=\"inh-risk-val\">12</p>\n<p id=\"inh-risk-label\" style=\"margin-top:6px;\"><span class=\"risk-level-pill risk-pill-high\">Alto</span></p>\n</div>\n</div>\n<div>\n<p style=\"font-size:0.8rem; font-weight:600; color:var(--ice); margin-bottom:1rem; text-transform:uppercase; letter-spacing:0.08em;\">Riesgo Residual (con controles)</p>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Probabilidad residual</label>\n<div class=\"lab-scale\" id=\"scale-prob-res\">\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_res',1,this)\">1</button>\n<button class=\"lab-scale-btn selected-1\" onclick=\"setRisk('prob_res',2,this)\">2</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_res',3,this)\">3</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_res',4,this)\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('prob_res',5,this)\">5</button>\n</div>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Impacto residual</label>\n<div class=\"lab-scale\" id=\"scale-imp-res\">\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_res',1,this)\">1</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_res',2,this)\">2</button>\n<button class=\"lab-scale-btn selected-3\" onclick=\"setRisk('imp_res',3,this)\">3</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_res',4,this)\">4</button>\n<button class=\"lab-scale-btn\" onclick=\"setRisk('imp_res',5,this)\">5</button>\n</div>\n</div>\n<div class=\"result-card\">\n<p class=\"result-label\">Nivel de riesgo residual</p>\n<p class=\"result-value\" id=\"res-risk-val\">6</p>\n<p id=\"res-risk-label\" style=\"margin-top:6px;\"><span class=\"risk-level-pill risk-pill-med\">Medio</span></p>\n</div>\n</div>\n</div>\n<div style=\"margin-top:1.5rem;\">\n<p style=\"font-size:0.75rem; font-weight:600; color:var(--ice); margin-bottom:0.75rem; text-transform:uppercase; letter-spacing:0.08em;\">Matriz de riesgo — visualización</p>\n<div class=\"risk-matrix\" id=\"risk-matrix-viz\">\n<div class=\"rm-cell rm-label\"></div>\n<div class=\"rm-cell rm-header\">P=1</div>\n<div class=\"rm-cell rm-header\">P=2</div>\n<div class=\"rm-cell rm-header\">P=3</div>\n<div class=\"rm-cell rm-header\">P=4</div>\n<div class=\"rm-cell rm-header\">P=5</div>\n<!-- fila I=5 -->\n<div class=\"rm-cell rm-header\">I=5</div>\n<div class=\"rm-cell rm-med\" data-i=\"5\" data-p=\"1\">5</div>\n<div class=\"rm-cell rm-high\" data-i=\"5\" data-p=\"2\">10</div>\n<div class=\"rm-cell rm-high\" data-i=\"5\" data-p=\"3\">15</div>\n<div class=\"rm-cell rm-high\" data-i=\"5\" data-p=\"4\">20</div>\n<div class=\"rm-cell rm-high\" data-i=\"5\" data-p=\"5\">25</div>\n<!-- I=4 -->\n<div class=\"rm-cell rm-header\">I=4</div>\n<div class=\"rm-cell rm-low\" data-i=\"4\" data-p=\"1\">4</div>\n<div class=\"rm-cell rm-med\" data-i=\"4\" data-p=\"2\">8</div>\n<div class=\"rm-cell rm-high\" data-i=\"4\" data-p=\"3\">12</div>\n<div class=\"rm-cell rm-high\" data-i=\"4\" data-p=\"4\">16</div>\n<div class=\"rm-cell rm-high\" data-i=\"4\" data-p=\"5\">20</div>\n<!-- I=3 -->\n<div class=\"rm-cell rm-header\">I=3</div>\n<div class=\"rm-cell rm-low\" data-i=\"3\" data-p=\"1\">3</div>\n<div class=\"rm-cell rm-med\" data-i=\"3\" data-p=\"2\">6</div>\n<div class=\"rm-cell rm-med\" data-i=\"3\" data-p=\"3\">9</div>\n<div class=\"rm-cell rm-high\" data-i=\"3\" data-p=\"4\">12</div>\n<div class=\"rm-cell rm-high\" data-i=\"3\" data-p=\"5\">15</div>\n<!-- I=2 -->\n<div class=\"rm-cell rm-header\">I=2</div>\n<div class=\"rm-cell rm-low\" data-i=\"2\" data-p=\"1\">2</div>\n<div class=\"rm-cell rm-low\" data-i=\"2\" data-p=\"2\">4</div>\n<div class=\"rm-cell rm-med\" data-i=\"2\" data-p=\"3\">6</div>\n<div class=\"rm-cell rm-med\" data-i=\"2\" data-p=\"4\">8</div>\n<div class=\"rm-cell rm-high\" data-i=\"2\" data-p=\"5\">10</div>\n<!-- I=1 -->\n<div class=\"rm-cell rm-header\">I=1</div>\n<div class=\"rm-cell rm-low\" data-i=\"1\" data-p=\"1\">1</div>\n<div class=\"rm-cell rm-low\" data-i=\"1\" data-p=\"2\">2</div>\n<div class=\"rm-cell rm-low\" data-i=\"1\" data-p=\"3\">3</div>\n<div class=\"rm-cell rm-med\" data-i=\"1\" data-p=\"4\">4</div>\n<div class=\"rm-cell rm-med\" data-i=\"1\" data-p=\"5\">5</div>\n</div>\n<p style=\"font-size:0.7rem; color:var(--text-faint); margin-top:0.5rem;\">🟢 Bajo (1–4)    🟡 Medio (5–9)    🔴 Alto (10–25)</p>\n</div>\n<div class=\"lab-nav\">\n<button class=\"lab-btn\" onclick=\"labPrev(3)\">← Volver</button>\n<button class=\"lab-btn lab-btn--primary\" onclick=\"labNext(3)\">Siguiente: Decisión de tratamiento →</button>\n</div>\n</div>\n<!-- PASO 5: Tratamiento y resumen -->\n<div class=\"lab-step\" id=\"step-4\">\n<div class=\"lab-step-header\">\n<span class=\"lab-step-num\">PASO 5 DE 5</span>\n<span class=\"lab-step-title\">Decisión de tratamiento y ficha de riesgo</span>\n</div>\n<div style=\"display:grid; grid-template-columns:1fr 1fr; gap:1rem; margin-bottom:1.5rem;\">\n<div class=\"lab-field\">\n<label class=\"lab-label\">Opción de tratamiento</label>\n<select class=\"lab-select\" id=\"treatment-select\">\n<option value=\"modificar\">Modificar (implementar controles)</option>\n<option value=\"retener\">Retener (aceptar riesgo residual)</option>\n<option value=\"evitar\">Evitar (eliminar la actividad)</option>\n<option value=\"compartir\">Compartir (transferir/seguro)</option>\n</select>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Propietario del riesgo</label>\n<input class=\"lab-input\" id=\"risk-owner\" type=\"text\" value=\"Director Comercial / CISO\"/>\n</div>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Controles seleccionados (Anexo A)</label>\n<input class=\"lab-input\" id=\"controls-selected\" type=\"text\" value=\"8.13 (Backup), 8.14 (Redundancia TIC), 5.30 (Continuidad), 8.8 (Gestión vulnerabilidades)\"/>\n</div>\n<div class=\"lab-field\">\n<label class=\"lab-label\">Fecha de revisión del riesgo</label>\n<input class=\"lab-input\" id=\"review-date\" type=\"date\" value=\"2025-12-31\"/>\n</div>\n<!-- FICHA DE RIESGO GENERADA -->\n<div id=\"risk-card-output\" style=\"background:rgba(255,255,255,0.04); border:1px solid rgba(0,200,150,0.2); border-radius:var(--radius-lg); padding:1.75rem; margin-top:1.5rem;\">\n<div style=\"display:flex; align-items:center; justify-content:space-between; margin-bottom:1.25rem; padding-bottom:1rem; border-bottom:1px solid rgba(168,200,232,0.1);\">\n<div>\n<p style=\"font-size:0.65rem; font-weight:700; color:var(--accent); text-transform:uppercase; letter-spacing:0.1em; margin-bottom:4px;\">Ficha de Riesgo</p>\n<p id=\"rc-asset-name\" style=\"font-size:1rem; font-weight:700; color:var(--white);\">Base de datos de clientes (CRM)</p>\n</div>\n<span class=\"risk-level-pill risk-pill-med\" id=\"rc-residual-pill\">Residual: Medio</span>\n</div>\n<div style=\"display:grid; grid-template-columns:1fr 1fr 1fr; gap:1rem; margin-bottom:1.25rem;\">\n<div><p class=\"result-label\">Amenaza</p><p id=\"rc-threat\" style=\"font-size:0.85rem; color:var(--ice); font-weight:500;\">Ransomware</p></div>\n<div><p class=\"result-label\">Riesgo inherente</p><p id=\"rc-inh\" style=\"font-size:0.85rem; color:#FCA5A5; font-weight:700;\">12 — Alto</p></div>\n<div><p class=\"result-label\">Riesgo residual</p><p id=\"rc-res\" style=\"font-size:0.85rem; color:var(--warn); font-weight:700;\">6 — Medio</p></div>\n</div>\n<div style=\"display:grid; grid-template-columns:1fr 1fr; gap:1rem;\">\n<div><p class=\"result-label\">Tratamiento</p><p id=\"rc-treatment\" style=\"font-size:0.85rem; color:var(--ice); font-weight:500;\">Modificar</p></div>\n<div><p class=\"result-label\">Propietario</p><p id=\"rc-owner\" style=\"font-size:0.85rem; color:var(--ice); font-weight:500;\">Director Comercial / CISO</p></div>\n</div>\n<div style=\"margin-top:1rem; padding-top:1rem; border-top:1px solid rgba(168,200,232,0.1);\">\n<p class=\"result-label\">Controles aplicados</p>\n<p id=\"rc-controls\" style=\"font-size:0.82rem; color:var(--ice);\">8.13 (Backup), 8.14 (Redundancia TIC), 5.30 (Continuidad), 8.8 (Gestión vulnerabilidades)</p>\n</div>\n</div>\n<div class=\"lab-nav\">\n<button class=\"lab-btn\" onclick=\"labPrev(4)\">← Volver</button>\n<button class=\"lab-btn lab-btn--primary\" onclick=\"generateFinalCard()\">✓ Generar ficha de riesgo</button>\n</div>\n</div>\n</div>"}, {"type": "resumen"}];
